# --- Authentication Middleware ---

# Simulates authentication by reading an X-User-ID header
# and setting context_value["current_user"] for resolvers.
# In production, this would validate JWT tokens, session cookies, etc.

AUTH_TOKEN_MAP = {
    "token-alice": "1",
    "token-bob": "2",
    "token-charlie": "3",
}


def get_context_value(request):
    """Build the GraphQL context from the incoming request."""
    # Extract auth token from Authorization header
    auth_header = request.headers.get("Authorization", "")
    current_user = None

    if auth_header.startswith("Bearer "):
        token = auth_header[len("Bearer "):]
        user_id = AUTH_TOKEN_MAP.get(token)
        if user_id and user_id in USERS:
            current_user = USERS[user_id]

    # Also support simple X-User-ID header for easier testing
    user_id_header = request.headers.get("X-User-ID")
    if user_id_header and user_id_header in USERS and current_user is None:
        current_user = USERS[user_id_header]

    return {
        "request": request,
        "current_user": current_user,
    }


# --- Query Resolvers ---

query = QueryType()


@query.field("me")
def resolve_me(_, info):
    """Return the currently authenticated user."""
    current_user = info.context.get("current_user")
    if current_user is None:
        return None
    return current_user


@query.field("user")
def resolve_user(_, info, id):
    """Fetch a user by ID."""
    return USERS.get(id)


@query.field("users")
def resolve_users(_, info):
    """Fetch all users."""
    return list(USERS.values())


@query.field("post")
def resolve_post(_, info, id):
    """Fetch a single post by ID."""
    return POSTS.get(id)


@query.field("posts")
def resolve_posts(_, info):
    """Fetch all published posts. Includes unpublished posts if the author is the current user."""
    current_user = info.context.get("current_user")
    result = []
    for post in POSTS.values():
        if post["published"]:
            result.append(post)
        elif current_user and post["author_id"] == current_user["id"]:
            # Authors can see their own unpublished posts
            result.append(post)
    return result


